584	        event: &Event,
585	        ctx: &Context,
586	        props: &Props,
587	    ) -> Option<TransitionPlan<Self>> {
588	        match event {
589	            Event::Focus { is_keyboard } => {
590	                let is_keyboard = *is_keyboard;
591	                Some(
592	                    TransitionPlan::to(State::Focused)
593	                        .apply(move |ctx: &mut Context| {
594	                            ctx.focused = true;
595	
596	                            ctx.focus_visible = is_keyboard;
597	                        })
598	                        .with_effect(focus_change_effect(true)),
599	                )
600	            }
601	
602	            Event::Blur => Some(
603	                TransitionPlan::to(State::Idle)
604	                    .apply(|ctx: &mut Context| {
605	                        ctx.focused = false;
606	
607	                        ctx.focus_visible = false;
608	                    })
609	                    .with_effect(focus_change_effect(false)),
610	            ),
611	
612	            Event::Change(value) => {
613	                if ctx.disabled || ctx.readonly || ctx.is_composing {
614	                    return None;
615	                }
616	
617	                let value = value.clone();
618	                Some(
619	                    TransitionPlan::context_only({
620	                        let value = value.clone();
621	                        move |ctx: &mut Context| {
622	                            if !ctx.value.is_controlled() {
623	                                ctx.value.set(value);
624	                            }
625	                        }
626	                    })
627	                    .with_effect(value_change_effect(value)),
628	                )
629	            }
630	
631	            Event::Clear => {
632	                if ctx.disabled || ctx.readonly {
633	                    return None;
634	                }
635	
636	                Some(
637	                    TransitionPlan::context_only(|ctx: &mut Context| {
638	                        if !ctx.value.is_controlled() {
639	                            ctx.value.set(String::new());
640	                        }
641	                    })
642	                    .with_effect(value_change_effect(String::new())),
643	                )
644	            }
645	
646	            Event::SetInvalid(invalid) => {
647	                let invalid = *invalid;
648	                Some(TransitionPlan::context_only(move |ctx: &mut Context| {
649	                    ctx.invalid = invalid;
650	                }))
651	            }
652	
653	            Event::CompositionStart => Some(TransitionPlan::context_only(|ctx: &mut Context| {
654	                ctx.is_composing = true;
655	            })),
656	
657	            Event::CompositionEnd(value) => {
658	                let value = value.clone();
659	
660	                let should_change = !ctx.disabled && !ctx.readonly;
661	
662	                let mut plan = TransitionPlan::context_only({
663	                    let value = value.clone();
664	                    move |ctx: &mut Context| {
665	                        ctx.is_composing = false;
666	
667	                        if should_change && !ctx.value.is_controlled() {
668	                            ctx.value.set(value);
669	                        }
670	                    }
671	                });
672	
673	                if should_change {
674	                    plan = plan.with_effect(value_change_effect(value));
675	                }
676	
677	                Some(plan)
678	            }
679	
680	            Event::SetValue(value) => {
681	                let value = value.clone();
682	                Some(TransitionPlan::context_only(move |ctx: &mut Context| {
683	                    if let Some(value) = value {
684	                        ctx.value.set(value.clone());
685	
686	                        ctx.value.sync_controlled(Some(value));
687	                    } else {
688	                        ctx.value.sync_controlled(None);
689	                    }
690	                }))
691	            }
692	
693	            Event::SetProps => {
694	                let props = props.clone();
695	                Some(TransitionPlan::context_only(move |ctx: &mut Context| {
696	                    ctx.disabled = props.disabled;
697	                    ctx.readonly = props.readonly;
698	                    ctx.invalid = props.invalid;
699	                    ctx.required = props.required;
700	                    ctx.placeholder = props.placeholder;
701	                    ctx.input_type = props.input_type;
702	                    ctx.max_length = props.max_length;
703	                    ctx.min_length = props.min_length;
704	                    ctx.pattern = props.pattern;
705	                    ctx.autocomplete = props.autocomplete;
706	                    ctx.name = props.name;
707	                    ctx.dir = props.dir;
708	                    ctx.input_mode = props.input_mode;
709	                }))
710	            }
