162	```rust
163	/// The machine for the PasswordInput component.
164	pub struct Machine;
165	
166	impl ars_core::Machine for Machine {
167	    type State = State;
168	    type Event = Event;
169	    type Context = Context;
170	    type Props = Props;
171	    type Api<'a> = Api<'a>;
172	    type Messages = Messages;
173	
174	    fn init(props: &Self::Props, env: &Env, messages: &Self::Messages) -> (Self::State, Self::Context) {
175	        let locale = env.locale.clone();
176	        let messages = messages.clone();
177	        let state = if props.default_visible { State::Visible } else { State::Masked };
178	        let ctx = Context {
179	            visible: props.default_visible,
180	            value: match &props.value {
181	                Some(v) => Bindable::controlled(v.clone()),
182	                None => Bindable::uncontrolled(props.default_value.clone()),
183	            },
184	            disabled: props.disabled,
185	            required: props.required,
186	            invalid: props.invalid,
187	            readonly: props.readonly,
188	            focused: false,
189	            focus_visible: false,
190	            has_description: false,
191	            locale,
192	            messages,
193	            ids: ComponentIds::from_id(&props.id),
194	        };
195	        (state, ctx)
196	    }
197	
198	    fn transition(
199	        state: &Self::State,
200	        event: &Self::Event,
201	        ctx: &Self::Context,
202	        _props: &Self::Props,
203	    ) -> Option<TransitionPlan<Self>> {
204	        match event {
205	            Event::ToggleVisibility => {
206	                let next_visible = !ctx.visible;
207	                Some(TransitionPlan::to(if next_visible {
208	                    State::Visible
209	                } else {
210	                    State::Masked
211	                }).apply(move |ctx| {
212	                    ctx.visible = next_visible;
213	                }))
214	            }
215	
216	            Event::SetVisibility(visible) => {
217	                if ctx.visible == *visible { return None; }
218	                let vis = *visible;
219	                Some(TransitionPlan::to(if vis {
220	                    State::Visible
221	                } else {
222	                    State::Masked
223	                }).apply(move |ctx| {
224	                    ctx.visible = vis;
225	                }))
226	            }
227	
228	            Event::Focus { is_keyboard } => {
229	                let is_kb = *is_keyboard;
230	                Some(TransitionPlan::context_only(move |ctx| {
231	                    ctx.focused = true;
232	                    ctx.focus_visible = is_kb;
233	                }))
234	            }
235	
236	            Event::Blur => {
237	                Some(TransitionPlan::context_only(|ctx| {
238	                    ctx.focused = false;
239	                    ctx.focus_visible = false;
240	                }))
241	            }
242	        }
243	    }
244	
245	    fn connect<'a>(
246	        state: &'a Self::State,
247	        ctx: &'a Self::Context,
248	        props: &'a Self::Props,
249	        send: &'a dyn Fn(Self::Event),
250	    ) -> Self::Api<'a> {
251	        Api { state, ctx, props, send }
252	    }
253	}
254	```
