250	
251	```rust
252	/// The machine for the NumberInput component.
253	pub struct Machine;
254	
255	impl ars_core::Machine for Machine {
256	    type State = State;
257	    type Event = Event;
258	    type Context = Context;
259	    type Props = Props;
260	    type Api<'a> = Api<'a>;
261	    type Messages = Messages;
262	
263	    fn init(props: &Self::Props, env: &Env, messages: &Self::Messages) -> (Self::State, Self::Context) {
264	        let locale = env.locale.clone();
265	        let messages = messages.clone();
266	        let state = State::Idle;
267	        let ctx = Context {
268	            value: match props.value {
269	                Some(v) => Bindable::controlled(Some(v)),
270	                None => Bindable::uncontrolled(props.default_value),
271	            },
272	            min: props.min,
273	            max: props.max,
274	            step: props.step,
275	            large_step: props.large_step,
276	            precision: props.precision,
277	            disabled: props.disabled,
278	            readonly: props.readonly,
279	            invalid: props.invalid,
280	            required: props.required,
281	            focused: false,
282	            focus_visible: false,
283	            name: props.name.clone(),
284	            spin_on_press: props.spin_on_press,
285	            scrubbing: false,
286	            is_composing: false,
287	            has_description: false,
288	            locale,
289	            messages,
290	            ids: ComponentIds::from_id(&props.id),
291	        };
292	        (state, ctx)
293	    }
294	
295	    fn transition(
296	        state: &Self::State,
297	        event: &Self::Event,
298	        ctx: &Self::Context,
299	        props: &Self::Props,
300	    ) -> Option<TransitionPlan<Self>> {
301	        if ctx.disabled || ctx.readonly {
302	            match event {
303	                Event::Increment | Event::Decrement
304	                | Event::IncrementLarge | Event::DecrementLarge
305	                | Event::IncrementToMax | Event::DecrementToMin
306	                | Event::Change(_) | Event::SetValue(_)
307	                | Event::StartScrub | Event::Scrub(_) | Event::EndScrub
308	                | Event::Wheel { .. } => return None,
309	                _ => {}
310	            }
311	        }
312	
313	        match event {
314	            Event::Focus { is_keyboard } => {
315	                let is_kb = *is_keyboard;
316	                Some(TransitionPlan::to(State::Focused).apply(move |ctx| {
317	                    ctx.focused = true;
318	                    ctx.focus_visible = is_kb;
319	                }))
320	            }
321	            Event::Blur => {
322	                let clamp_min = ctx.min;
323	                let clamp_max = ctx.max;
324	                let current_val = *ctx.value.get();
325	                let clamp_on_blur = props.clamp_value_on_blur;
326	                let precision = ctx.precision;
327	                Some(TransitionPlan::to(State::Idle).apply(move |ctx| {
328	                    ctx.focused = false;
329	                    ctx.focus_visible = false;
330	                    if clamp_on_blur {
331	                        if let Some(val) = current_val {
332	                            let clamped = val.clamp(clamp_min, clamp_max);
333	                            if clamped != val {
334	                                ctx.value.set(Some(round_to_precision(clamped, precision)));
335	                            }
336	                        }
337	                    }
338	                }))
339	            }
340	            Event::Increment => {
341	                let current = ctx.value.get().unwrap_or(ctx.min);
342	                let next = round_to_precision((current + ctx.step).min(ctx.max), ctx.precision);
343	                Some(TransitionPlan::context_only(move |ctx| { ctx.value.set(Some(next)); }))
344	            }
345	            Event::Decrement => {
346	                let current = ctx.value.get().unwrap_or(ctx.min);
347	                let prev = round_to_precision((current - ctx.step).max(ctx.min), ctx.precision);
348	                Some(TransitionPlan::context_only(move |ctx| { ctx.value.set(Some(prev)); }))
349	            }
350	            Event::IncrementLarge => {
351	                let current = ctx.value.get().unwrap_or(ctx.min);
352	                let next = round_to_precision((current + ctx.large_step).min(ctx.max), ctx.precision);
353	                Some(TransitionPlan::context_only(move |ctx| { ctx.value.set(Some(next)); }))
354	            }
355	            Event::DecrementLarge => {
356	                let current = ctx.value.get().unwrap_or(ctx.min);
357	                let prev = round_to_precision((current - ctx.large_step).max(ctx.min), ctx.precision);
358	                Some(TransitionPlan::context_only(move |ctx| { ctx.value.set(Some(prev)); }))
359	            }
360	            Event::IncrementToMax => {
361	                let max = ctx.max;
362	                Some(TransitionPlan::context_only(move |ctx| { ctx.value.set(Some(max)); }))
363	            }
364	            Event::DecrementToMin => {
365	                let min = ctx.min;
366	                Some(TransitionPlan::context_only(move |ctx| { ctx.value.set(Some(min)); }))
367	            }
368	            Event::SetValue(val) => {
369	                let rounded = round_to_precision(val.clamp(ctx.min, ctx.max), ctx.precision);
370	                Some(TransitionPlan::context_only(move |ctx| { ctx.value.set(Some(rounded)); }))
371	            }
372	            Event::Change(text) => {
373	                let text = text.clone();
374	                Some(TransitionPlan::context_only(move |ctx| {
375	                    if text.is_empty() {
376	                        ctx.value.set(None);
377	                    } else if let Ok(val) = text.parse::<f64>() {
378	                        ctx.value.set(Some(val));
379	                    }
380	                }))
381	            }
382	            Event::StartScrub => {
383	                Some(TransitionPlan::to(State::Scrubbing).apply(|ctx| { ctx.scrubbing = true; }))
384	            }
385	            Event::Scrub(delta) if matches!(state, State::Scrubbing) => {
386	                let current = ctx.value.get().unwrap_or(0.0);
387	                let next = round_to_precision((current + delta * ctx.step).clamp(ctx.min, ctx.max), ctx.precision);
388	                Some(TransitionPlan::context_only(move |ctx| { ctx.value.set(Some(next)); }))
389	            }
390	            Event::EndScrub => {
391	                let is_focused = ctx.focused;
392	                Some(TransitionPlan::to(if is_focused { State::Focused } else { State::Idle })
393	                    .apply(|ctx| { ctx.scrubbing = false; }))
394	            }
395	            Event::Wheel { delta } if matches!(state, State::Focused) && !ctx.readonly && props.allow_mouse_wheel => {
396	                let event = if *delta > 0.0 { Event::Increment } else { Event::Decrement };
397	                Self::transition(state, &event, ctx, props)
398	            }
399	            Event::CompositionStart => {
400	                Some(TransitionPlan::context_only(|ctx| { ctx.is_composing = true; }))
401	            }
402	            Event::CompositionEnd => {
403	                Some(TransitionPlan::context_only(|ctx| { ctx.is_composing = false; }))
404	            }
405	            _ => None,
406	        }
407	    }
408	
409	    fn connect<'a>(
410	        state: &'a Self::State,
411	        ctx: &'a Self::Context,
412	        props: &'a Self::Props,
413	        send: &'a dyn Fn(Self::Event),
414	    ) -> Self::Api<'a> {
415	        Api { state, ctx, props, send }
416	    }
417	}
