435	/// The API for the NumberInput component.
436	pub struct Api<'a> {
437	    state: &'a State,
438	    ctx: &'a Context,
439	    props: &'a Props,
440	    send: &'a dyn Fn(Event),
441	}
442	
443	impl<'a> Api<'a> {
444	    /// Attributes for the root container.
445	    pub fn root_attrs(&self) -> AttrMap {
446	        let mut attrs = AttrMap::new();
447	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Root.data_attrs();
448	        attrs.set(scope_attr, scope_val);
449	        attrs.set(part_attr, part_val);
450	        attrs.set(HtmlAttr::Data("ars-state"), match self.state {
451	            State::Idle => "idle",
452	            State::Focused => "focused",
453	            State::Scrubbing => "scrubbing",
454	        });
455	        if self.ctx.disabled { attrs.set_bool(HtmlAttr::Data("ars-disabled"), true); }
456	        if self.ctx.invalid { attrs.set_bool(HtmlAttr::Data("ars-invalid"), true); }
457	        if self.ctx.readonly { attrs.set_bool(HtmlAttr::Data("ars-readonly"), true); }
458	        if self.ctx.focus_visible { attrs.set_bool(HtmlAttr::Data("ars-focus-visible"), true); }
459	        attrs
460	    }
461	
462	    /// Attributes for the label element.
463	    pub fn label_attrs(&self) -> AttrMap {
464	        let mut attrs = AttrMap::new();
465	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Label.data_attrs();
466	        attrs.set(scope_attr, scope_val);
467	        attrs.set(part_attr, part_val);
468	        attrs.set(HtmlAttr::Id, self.ctx.ids.part("label"));
469	        attrs.set(HtmlAttr::For, self.ctx.ids.part("input"));
470	        attrs
471	    }
472	
473	    /// Attributes for the native input element.
474	    pub fn input_attrs(&self) -> AttrMap {
475	        let mut attrs = AttrMap::new();
476	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Input.data_attrs();
477	        attrs.set(scope_attr, scope_val);
478	        attrs.set(part_attr, part_val);
479	        attrs.set(HtmlAttr::Id, self.ctx.ids.part("input"));
480	        attrs.set(HtmlAttr::Role, "spinbutton");
481	        attrs.set(HtmlAttr::InputMode, "decimal");
482	        if let Some(val) = self.ctx.value.get() {
483	            attrs.set(HtmlAttr::Aria(AriaAttr::ValueNow), val.to_string());
484	        }
485	        if self.ctx.min.is_finite() {
486	            attrs.set(HtmlAttr::Aria(AriaAttr::ValueMin), self.ctx.min.to_string());
487	        }
488	        if self.ctx.max.is_finite() {
489	            attrs.set(HtmlAttr::Aria(AriaAttr::ValueMax), self.ctx.max.to_string());
490	        }
491	        // aria-valuetext should be set by the adapter using locale-formatted value
492	        attrs.set(HtmlAttr::Aria(AriaAttr::LabelledBy), self.ctx.ids.part("label"));
493	        if self.ctx.has_description {
494	            let mut describedby_parts = Vec::new();
495	            describedby_parts.push(self.ctx.ids.part("description"));
496	            if self.ctx.invalid {
497	                describedby_parts.push(self.ctx.ids.part("error-message"));
498	            }
499	            attrs.set(HtmlAttr::Aria(AriaAttr::DescribedBy), describedby_parts.join(" "));
500	        } else if self.ctx.invalid {
501	            attrs.set(HtmlAttr::Aria(AriaAttr::DescribedBy), self.ctx.ids.part("error-message"));
502	        }
503	        if self.ctx.required { attrs.set(HtmlAttr::Aria(AriaAttr::Required), "true"); }
504	        if self.ctx.invalid { attrs.set(HtmlAttr::Aria(AriaAttr::Invalid), "true"); }
505	        if self.ctx.disabled { attrs.set_bool(HtmlAttr::Disabled, true); }
506	        if self.ctx.readonly { attrs.set_bool(HtmlAttr::ReadOnly, true); }
507	        if let Some(ref name) = self.ctx.name { attrs.set(HtmlAttr::Name, name); }
508	        if let Some(ref form) = self.props.form { attrs.set(HtmlAttr::Form, form); }
509	        attrs
510	    }
511	
512	    /// Attributes for the increment trigger button.
513	    /// **Spin-on-press behavior:** When `ctx.spin_on_press` is `true`, the adapter
514	    /// attaches `pointerdown` on increment/decrement triggers to start a repeating
515	    /// timer that sends `Event::Increment`/`Event::Decrement` with accelerating
516	    /// speed: initial delay 400ms, then 50ms intervals. The timer stops on
517	    /// `pointerup`/`pointerleave`. When `false`, each click sends a single event.
518	    pub fn increment_trigger_attrs(&self) -> AttrMap {
519	        let mut attrs = AttrMap::new();
520	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::IncrementTrigger.data_attrs();
521	        attrs.set(scope_attr, scope_val);
522	        attrs.set(part_attr, part_val);
523	        attrs.set(HtmlAttr::Type, "button");
524	        attrs.set(HtmlAttr::Aria(AriaAttr::Label), (self.ctx.messages.increment_label)(&self.ctx.locale));
525	        attrs.set(HtmlAttr::TabIndex, "-1");
526	        if self.ctx.disabled || self.ctx.readonly {
527	            attrs.set_bool(HtmlAttr::Disabled, true);
528	        }
529	        // Disable at max boundary
530	        if let Some(val) = self.ctx.value.get() {
531	            if *val >= self.ctx.max { attrs.set_bool(HtmlAttr::Disabled, true); }
532	        }
533	        attrs
534	    }
535	
536	    /// Attributes for the decrement trigger button.
537	    pub fn decrement_trigger_attrs(&self) -> AttrMap {
538	        let mut attrs = AttrMap::new();
539	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::DecrementTrigger.data_attrs();
540	        attrs.set(scope_attr, scope_val);
541	        attrs.set(part_attr, part_val);
542	        attrs.set(HtmlAttr::Type, "button");
543	        attrs.set(HtmlAttr::Aria(AriaAttr::Label), (self.ctx.messages.decrement_label)(&self.ctx.locale));
544	        attrs.set(HtmlAttr::TabIndex, "-1");
545	        if self.ctx.disabled || self.ctx.readonly {
546	            attrs.set_bool(HtmlAttr::Disabled, true);
547	        }
548	        // Disable at min boundary
549	        if let Some(val) = self.ctx.value.get() {
550	            if *val <= self.ctx.min { attrs.set_bool(HtmlAttr::Disabled, true); }
551	        }
552	        attrs
553	    }
554	
555	    /// Attributes for the description/help text element.
556	    pub fn description_attrs(&self) -> AttrMap {
557	        let mut attrs = AttrMap::new();
558	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Description.data_attrs();
559	        attrs.set(scope_attr, scope_val);
560	        attrs.set(part_attr, part_val);
561	        attrs.set(HtmlAttr::Id, self.ctx.ids.part("description"));
562	        attrs
563	    }
564	
565	    /// Attributes for the error message element.
566	    pub fn error_message_attrs(&self) -> AttrMap {
567	        let mut attrs = AttrMap::new();
568	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::ErrorMessage.data_attrs();
569	        attrs.set(scope_attr, scope_val);
570	        attrs.set(part_attr, part_val);
571	        attrs.set(HtmlAttr::Id, self.ctx.ids.part("error-message"));
572	        attrs.set(HtmlAttr::Aria(AriaAttr::Live), "polite");
573	        attrs
574	    }
575	
576	    pub fn on_input_focus(&self, is_keyboard: bool) { (self.send)(Event::Focus { is_keyboard }); }
577	    pub fn on_input_blur(&self) { (self.send)(Event::Blur); }
578	    pub fn on_input_change(&self, text: String) { (self.send)(Event::Change(text)); }
579	    pub fn on_increment_click(&self) { (self.send)(Event::Increment); }
580	    pub fn on_decrement_click(&self) { (self.send)(Event::Decrement); }
581	
582	    pub fn on_input_keydown(&self, data: &KeyboardEventData) {
583	        let event = match data.key {
584	            KeyboardKey::ArrowUp => Some(Event::Increment),
585	            KeyboardKey::ArrowDown => Some(Event::Decrement),
586	            KeyboardKey::PageUp => Some(Event::IncrementLarge),
587	            KeyboardKey::PageDown => Some(Event::DecrementLarge),
588	            KeyboardKey::Home => Some(Event::DecrementToMin),
589	            KeyboardKey::End => Some(Event::IncrementToMax),
590	            _ => None,
591	        };
592	        if let Some(e) = event { (self.send)(e); }
593	    }
594	}
