229	
230	```rust
231	/// Machine for the PinInput component.
232	pub struct Machine;
233	
234	impl ars_core::Machine for Machine {
235	    type State = State;
236	    type Event = Event;
237	    type Context = Context;
238	    type Props = Props;
239	    type Api<'a> = Api<'a>;
240	    type Messages = Messages;
241	
242	    fn init(props: &Self::Props, env: &Env, messages: &Self::Messages) -> (Self::State, Self::Context) {
243	        let locale = env.locale.clone();
244	        let messages = messages.clone();
245	        let initial = props.value.clone()
246	            .unwrap_or_else(|| {
247	                let mut v = props.default_value.clone();
248	                v.resize(props.length, String::new());
249	                v
250	            });
251	        let complete = initial.iter().all(|v| !v.is_empty());
252	        let state = if complete { State::Completed } else { State::Idle };
253	        let ctx = Context {
254	            value: match &props.value {
255	                Some(v) => Bindable::controlled(v.clone()),
256	                None => Bindable::uncontrolled(initial),
257	            },
258	            length: props.length,
259	            disabled: props.disabled,
260	            invalid: props.invalid,
261	            otp: props.otp,
262	            mask: props.mask,
263	            placeholder: props.placeholder.clone(),
264	            focused_index: None,
265	            focus_visible: false,
266	            complete,
267	            mode: props.mode.clone(),
268	            name: props.name.clone(),
269	            select_on_focus: props.select_on_focus,
270	            blur_on_complete: props.blur_on_complete,
271	            is_composing: false,
272	            has_description: false,
273	            locale,
274	            messages,
275	            ids: ComponentIds::from_id(&props.id),
276	        };
277	        (state, ctx)
278	    }
279	
280	    fn transition(
281	        state: &Self::State,
282	        event: &Self::Event,
283	        ctx: &Self::Context,
284	        props: &Self::Props,
285	    ) -> Option<TransitionPlan<Self>> {
286	        // Disabled guard
287	        if ctx.disabled {
288	            match event {
289	                Event::InputChar { .. } | Event::DeleteChar { .. }
290	                | Event::Paste(_) | Event::Clear | Event::Complete(_) => return None,
291	                _ => {}
292	            }
293	        }
294	
295	        match (state, event) {
296	            // ── Focus / Blur ──────────────────────────────────────
297	            // When `ctx.select_on_focus` is true, the adapter calls `.select()` on the
298	            // input element after this transition completes. The machine only sets state;
299	            // the adapter reads `ctx.select_on_focus` in its focus event handler.
300	            (_, Event::Focus { index, is_keyboard }) => {
301	                let idx = *index;
302	                let is_kb = *is_keyboard;
303	                Some(TransitionPlan::to(State::Focused { index: idx }).apply(move |ctx| {
304	                    ctx.focused_index = Some(idx);
305	                    ctx.focus_visible = is_kb;
306	                }))
307	            }
308	            (_, Event::Blur) => {
309	                Some(TransitionPlan::to(if ctx.complete { State::Completed } else { State::Idle })
310	                    .apply(|ctx| {
311	                        ctx.focused_index = None;
312	                        ctx.focus_visible = false;
313	                    }))
314	            }
315	
316	            // ── InputChar ─────────────────────────────────────────
317	            (State::Focused { .. }, Event::InputChar { index, char: c }) => {
318	                let c = *c;
319	                let i = *index;
320	                let length = ctx.length;
321	                let mut vals = ctx.value.get().clone();
322	                vals[i] = c.to_string();
323	
324	                if vals.iter().all(|v| !v.is_empty()) {
325	                    let combined = vals.iter().map(|v| v.as_str()).collect::<String>();
326	                    let blur = ctx.blur_on_complete;
327	                    let mut plan = TransitionPlan::to(State::Completed).apply(move |ctx| {
328	                        ctx.value.set(vals);
329	                        ctx.complete = true;
330	                    }).with_effect(PendingEffect::new("complete", move |_ctx, props, _send| {
331	                        if let Some(ref cb) = props.on_value_complete {
332	                            let cb = cb.clone();
333	                            Box::new(move || { cb(&combined); })
334	                        } else {
335	                            no_cleanup()
336	                        }
337	                    }));
338	                    if blur {
339	                        plan = plan.with_effect(PendingEffect::new("blur-on-complete", |_ctx, _props, _send| {
340	                            let platform = use_platform_effects();
341	                            platform.focus_body();
342	                            no_cleanup()
343	                        }));
344	                    }
345	                    Some(plan)
346	                } else {
347	                    let next = (i + 1..length).find(|j| vals[*j].is_empty()).unwrap_or(i);
348	                    Some(TransitionPlan::to(State::Focused { index: next }).apply(move |ctx| {
349	                        ctx.value.set(vals);
350	                        ctx.focused_index = Some(next);
351	                    }).with_effect(PendingEffect::new("focus_element", |ctx, _props, _send| {
352	                        let platform = use_platform_effects();
353	                        let input_id = ctx.ids.item("input", ctx.focused_index.unwrap_or(0));
354	                        platform.focus_element_by_id(&input_id);
355	                        no_cleanup()
356	                    })))
357	                }
358	            }
359	
360	            // ── DeleteChar ────────────────────────────────────────
361	            (_, Event::DeleteChar { index }) => {
362	                let index = *index;
363	                let vals = ctx.value.get().clone();
364	                if vals[index].is_empty() && index > 0 {
365	                    let prev = index - 1;
366	                    Some(TransitionPlan::to(State::Focused { index: prev }).apply(move |ctx| {
367	                        let mut vals = ctx.value.get().clone();
368	                        vals[prev] = String::new();
369	                        ctx.value.set(vals);
370	                        ctx.focused_index = Some(prev);
371	                        ctx.complete = false;
372	                    }).with_effect(PendingEffect::new("focus_element", |ctx, _props, _send| {
373	                        let platform = use_platform_effects();
374	                        let input_id = ctx.ids.item("input", ctx.focused_index.unwrap_or(0));
375	                        platform.focus_element_by_id(&input_id);
376	                        no_cleanup()
377	                    })))
378	                } else {
379	                    Some(TransitionPlan::context_only(move |ctx| {
380	                        let mut vals = ctx.value.get().clone();
381	                        vals[index] = String::new();
382	                        ctx.value.set(vals);
383	                        ctx.complete = false;
384	                    }))
385	                }
386	            }
387	
388	            // ── Paste ─────────────────────────────────────────────
389	            (_, Event::Paste(text)) => {
390	                let mode = ctx.mode.clone();
391	                let chars = text.chars::<Vec<_>>()
392	                    .filter(|c| match mode {
393	                        Mode::Numeric => c.is_ascii_digit(),
394	                        Mode::Alphanumeric => c.is_alphanumeric(),
395	                        Mode::Password => true,
396	                    })
397	                    .take(ctx.length)
398	                    .collect();
399	                let mut vals = ctx.value.get().clone();
400	                let start = ctx.focused_index.unwrap_or(0);
401	                let length = ctx.length;
402	                for (i, ch) in chars.iter().enumerate() {
403	                    if start + i < length { vals[start + i] = ch.to_string(); }
404	                }
405	
406	                if vals.iter().all(|v| !v.is_empty()) {
407	                    let combined = vals.iter().map(|v| v.as_str()).collect::<String>();
408	                    let blur = ctx.blur_on_complete;
409	                    let mut plan = TransitionPlan::to(State::Completed).apply(move |ctx| {
410	                        ctx.value.set(vals);
411	                        ctx.complete = true;
412	                    }).with_effect(PendingEffect::new("complete", move |_ctx, props, _send| {
413	                        if let Some(ref cb) = props.on_value_complete {
414	                            let cb = cb.clone();
415	                            Box::new(move || { cb(&combined); })
416	                        } else { no_cleanup() }
417	                    }));
418	                    if blur {
419	                        plan = plan.with_effect(PendingEffect::new("blur-on-complete", |_ctx, _props, _send| {
420	                            let platform = use_platform_effects();
421	                            platform.focus_body();
422	                            no_cleanup()
423	                        }));
424	                    }
425	                    Some(plan)
426	                } else {
427	                    Some(TransitionPlan::context_only(move |ctx| { ctx.value.set(vals); }))
428	                }
429	            }
430	
431	            // ── Clear ─────────────────────────────────────────────
432	            (_, Event::Clear) => {
433	                let length = ctx.length;
434	                Some(TransitionPlan::to(State::Idle).apply(move |ctx| {
435	                    ctx.value.set(vec![String::new(); length]);
436	                    ctx.complete = false;
437	                    ctx.focused_index = None;
438	                }))
439	            }
440	
441	            // ── Navigation ────────────────────────────────────────
442	            (_, Event::FocusPrev) => {
443	                let current = ctx.focused_index.unwrap_or(0);
444	                if current == 0 { return None; }
445	                let prev = current - 1;
446	                Some(TransitionPlan::to(State::Focused { index: prev }).apply(move |ctx| {
447	                    ctx.focused_index = Some(prev);
448	                }).with_effect(PendingEffect::new("focus_element", |ctx, _props, _send| {
449	                    let platform = use_platform_effects();
450	                    let input_id = ctx.ids.item("input", ctx.focused_index.unwrap_or(0));
451	                    platform.focus_element_by_id(&input_id);
452	                    no_cleanup()
453	                })))
454	            }
455	
456	            (_, Event::FocusNext) => {
457	                let current = ctx.focused_index.unwrap_or(0);
458	                if current + 1 >= ctx.length { return None; }
459	                let next = current + 1;
460	                Some(TransitionPlan::to(State::Focused { index: next }).apply(move |ctx| {
461	                    ctx.focused_index = Some(next);
462	                }).with_effect(PendingEffect::new("focus_element", |ctx, _props, _send| {
463	                    let platform = use_platform_effects();
464	                    let input_id = ctx.ids.item("input", ctx.focused_index.unwrap_or(0));
465	                    platform.focus_element_by_id(&input_id);
466	                    no_cleanup()
467	                })))
468	            }
469	
470	            // ── IME Composition ───────────────────────────────────
471	            (_, Event::CompositionStart) => {
472	                Some(TransitionPlan::context_only(|ctx| { ctx.is_composing = true; }))
473	            }
474	            (_, Event::CompositionEnd) => {
475	                Some(TransitionPlan::context_only(|ctx| { ctx.is_composing = false; }))
476	            }
477	
478	            _ => None,
479	        }
480	    }
481	
482	    fn connect<'a>(
483	        state: &'a Self::State,
484	        ctx: &'a Self::Context,
485	        props: &'a Self::Props,
486	        send: &'a dyn Fn(Self::Event),
487	    ) -> Self::Api<'a> {
488	        Api { state, ctx, props, send }
489	    }
490	}
491	```
492	
493	### 1.6 Connect / API
494	
495	```rust
496	#[derive(ComponentPart)]
497	#[scope = "pin-input"]
498	pub enum Part {
499	    Root,
500	    Label,
501	    Input { cell_index: usize },       // cell index
502	    HiddenInput,
503	    Description,
504	    ErrorMessage,
505	}
506	
507	/// The API for the PinInput component.
508	pub struct Api<'a> {
509	    state: &'a State,
510	    ctx: &'a Context,
511	    props: &'a Props,
512	    send: &'a dyn Fn(Event),
513	}
514	
515	impl<'a> Api<'a> {
516	    /// Attributes for the root container.
517	    pub fn root_attrs(&self) -> AttrMap {
518	        let mut attrs = AttrMap::new();
519	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Root.data_attrs();
520	        attrs.set(scope_attr, scope_val);
521	        attrs.set(part_attr, part_val);
522	        attrs.set(HtmlAttr::Role, "group");
523	        attrs.set(HtmlAttr::Data("ars-state"), match self.state {
524	            State::Idle => "idle",
525	            State::Focused { .. } => "focused",
526	            State::Completed => "completed",
527	        });
528	        if self.ctx.disabled { attrs.set_bool(HtmlAttr::Data("ars-disabled"), true); }
529	        if self.ctx.invalid { attrs.set_bool(HtmlAttr::Data("ars-invalid"), true); }
530	        if self.ctx.focus_visible { attrs.set_bool(HtmlAttr::Data("ars-focus-visible"), true); }
531	        attrs
532	    }
533	
534	    /// Attributes for the group label.
535	    pub fn label_attrs(&self) -> AttrMap {
536	        let mut attrs = AttrMap::new();
537	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Label.data_attrs();
538	        attrs.set(scope_attr, scope_val);
539	        attrs.set(part_attr, part_val);
540	        attrs.set(HtmlAttr::Id, self.ctx.ids.part("label"));
541	        attrs
542	    }
543	
544	    /// Attributes for a single cell input.
545	    pub fn input_attrs(&self, index: usize) -> AttrMap {
546	        let mut attrs = AttrMap::new();
547	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Input { cell_index: index }.data_attrs();
548	        attrs.set(scope_attr, scope_val);
549	        attrs.set(part_attr, part_val);
550	        let input_id = self.ctx.ids.item("input", index);
551	        attrs.set(HtmlAttr::Id, input_id);
552	        attrs.set(HtmlAttr::Data("ars-index"), index.to_string());
553	        attrs.set(HtmlAttr::Type, if self.ctx.mask { "password" } else { "text" });
554	        attrs.set(HtmlAttr::InputMode, match self.ctx.mode {
555	            Mode::Numeric => "numeric",
556	            Mode::Alphanumeric | Mode::Password => "text",
557	        });
558	        attrs.set(HtmlAttr::MaxLength, "1");
559	        attrs.set(HtmlAttr::Aria(AriaAttr::Label),
560	            (self.ctx.messages.ordinal_label)(index + 1, self.ctx.length, &self.ctx.locale));
561	        if self.ctx.otp { attrs.set(HtmlAttr::Autocomplete, "one-time-code"); }
562	        if self.ctx.invalid { attrs.set(HtmlAttr::Aria(AriaAttr::Invalid), "true"); }
563	        if self.ctx.disabled { attrs.set_bool(HtmlAttr::Disabled, true); }
564	        if self.props.readonly { attrs.set_bool(HtmlAttr::ReadOnly, true); attrs.set(HtmlAttr::Aria(AriaAttr::ReadOnly), "true"); }
565	        let is_focused = self.ctx.focused_index == Some(index);
566	        attrs.set(HtmlAttr::TabIndex, if is_focused { "0" } else { "-1" });
567	        if let Some(ref val) = self.ctx.value.get().get(index) {
568	            if !val.is_empty() {
569	                attrs.set(HtmlAttr::Value, val);
570	            }
571	        }
572	        if let Some(ref ph) = self.ctx.placeholder {
573	            attrs.set(HtmlAttr::Placeholder, ph);
574	        }
575	        attrs
576	    }
577	
578	    /// Attributes for the hidden input (form submission).
579	    pub fn hidden_input_attrs(&self) -> AttrMap {
580	        let mut attrs = AttrMap::new();
581	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::HiddenInput.data_attrs();
582	        attrs.set(scope_attr, scope_val);
583	        attrs.set(part_attr, part_val);
584	        attrs.set(HtmlAttr::Type, "hidden");
585	        let combined = self.ctx.value.get().iter().map(|v| v.as_str()).collect::<String>();
586	        attrs.set(HtmlAttr::Value, combined);
587	        if let Some(ref name) = self.ctx.name { attrs.set(HtmlAttr::Name, name); }
588	        if let Some(ref form) = self.props.form { attrs.set(HtmlAttr::Form, form); }
589	        if self.props.required { attrs.set_bool(HtmlAttr::Required, true); }
590	        if self.ctx.disabled { attrs.set_bool(HtmlAttr::Disabled, true); }
591	        attrs.set(HtmlAttr::Aria(AriaAttr::Hidden), "true");
592	        attrs
593	    }
594	
595	    /// Attributes for the description/help text.
596	    pub fn description_attrs(&self) -> AttrMap {
597	        let mut attrs = AttrMap::new();
598	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Description.data_attrs();
599	        attrs.set(scope_attr, scope_val);
600	        attrs.set(part_attr, part_val);
601	        attrs.set(HtmlAttr::Id, self.ctx.ids.part("description"));
602	        attrs
603	    }
604	
605	    /// Attributes for the error message element.
606	    pub fn error_message_attrs(&self) -> AttrMap {
607	        let mut attrs = AttrMap::new();
608	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::ErrorMessage.data_attrs();
609	        attrs.set(scope_attr, scope_val);
610	        attrs.set(part_attr, part_val);
611	        attrs.set(HtmlAttr::Id, self.ctx.ids.part("error-message"));
612	        attrs.set(HtmlAttr::Aria(AriaAttr::Live), "polite");
613	        attrs
614	    }
615	
616	    pub fn on_cell_keydown(&self, index: usize, data: &KeyboardEventData) {
617	        match data.key {
618	            KeyboardKey::ArrowLeft => (self.send)(Event::FocusPrev),
619	            KeyboardKey::ArrowRight => (self.send)(Event::FocusNext),
620	            KeyboardKey::Backspace | KeyboardKey::Delete => (self.send)(Event::DeleteChar { index }),
621	            _ => {}
622	        }
623	    }
624	
625	    pub fn on_cell_focus(&self, index: usize, is_keyboard: bool) {
626	        (self.send)(Event::Focus { index, is_keyboard });
627	    }
628	
629	    pub fn on_cell_blur(&self) { (self.send)(Event::Blur); }
630	
631	    pub fn on_cell_input(&self, index: usize, ch: char) {
632	        (self.send)(Event::InputChar { index, char: ch });
633	    }
634	
635	    pub fn on_paste(&self, text: String) { (self.send)(Event::Paste(text)); }
636	}
637	
638	impl ConnectApi for Api<'_> {
639	    type Part = Part;
640	
641	    fn part_attrs(&self, part: Part) -> AttrMap {
642	        match part {
643	            Part::Root => self.root_attrs(),
644	            Part::Label => self.label_attrs(),
645	            Part::Input { cell_index } => self.input_attrs(cell_index),
646	            Part::HiddenInput => self.hidden_input_attrs(),
647	            Part::Description => self.description_attrs(),
648	            Part::ErrorMessage => self.error_message_attrs(),
649	        }
650	    }
651	}
652	```
653	
654	## 2. Anatomy
655	
656	```text
657	PinInput
658	├── Root               <div>    data-ars-scope="pin-input" data-ars-part="root" (role="group")
659	├── Label              <label>  data-ars-part="label"
660	├── Input (×N)         <input>  data-ars-part="input" data-ars-index="{n}"
661	├── HiddenInput        <input>  data-ars-part="hidden-input" (type="hidden", aria-hidden)
662	├── Description        <div>    data-ars-part="description" (optional)
663	└── ErrorMessage       <div>    data-ars-part="error-message" (optional)
664	```
665	
666	| Part         | Element   | Key Attributes                                             |
667	| ------------ | --------- | ---------------------------------------------------------- |
668	| Root         | `<div>`   | `role="group"`, `data-ars-state`                           |
669	| Label        | `<label>` | Group label                                                |
670	| Input        | `<input>` | Per-cell; `aria-label`, `maxlength="1"`, roving tabindex   |
671	| HiddenInput  | `<input>` | `type="hidden"` — combined value for form submission       |
672	| Description  | `<div>`   | Help text; linked via `aria-describedby` (optional)        |
673	| ErrorMessage | `<div>`   | Validation error; linked via `aria-describedby` (optional) |
674	
675	## 3. Accessibility
676	
677	### 3.1 ARIA Roles, States, and Properties
678	
679	| Property       | Element | Value                                                   |
680	| -------------- | ------- | ------------------------------------------------------- |
681	| `role`         | Root    | `group`                                                 |
682	| `aria-label`   | Input   | "Digit {n} of {total}" (localized via `ordinal_label`)  |
683	| `autocomplete` | Input   | `"one-time-code"` when `otp=true`                       |
684	| `inputmode`    | Input   | `"numeric"` (Numeric), `"text"` (Alphanumeric/Password) |
685	| `aria-invalid` | Input   | Present when group is invalid                           |
686	| `tabindex`     | Input   | Roving: focused cell `0`, all others `-1`               |
687	
688	### 3.2 Keyboard Interaction
689	
690	| Key            | Action                         |
691	| -------------- | ------------------------------ |
692	| 0-9 / a-z      | Fill cell, auto-advance        |
693	| Backspace      | Clear cell or move to previous |
694	| Delete         | Clear current cell             |
695	| ArrowLeft      | Move to previous cell          |
696	| ArrowRight     | Move to next cell              |
697	| Ctrl+V / Cmd+V | Paste across cells             |
698	
699	### 3.3 Screen Reader Guidance
700	
701	1. Each input field has `aria-label` in format `"Digit {n} of {total}"` (localized via `ars-i18n`).
702	2. On auto-advance, the screen reader announces the new field via focus move.
703	3. On paste, announce `"Code pasted"` via live region after all digits are filled.
704	4. Group container has `role="group"` with `aria-label` describing the purpose (e.g., "Verification code").
705	
706	## 4. Internationalization
707	
708	- Cell label `"Digit N of M"` uses ordinal formatting and localization via `Messages.ordinal_label`.
709	- Numeric mode filters based on Unicode digit category, not just ASCII 0-9.
710	- RTL: Cells render right-to-left; ArrowLeft moves forward visually (to the right in LTR).
711	
712	> **Timing protection:** For `Mode::Password`, the `Completed` state transition SHOULD be delayed by a configurable `submit_delay_ms` (default: 0, security-sensitive applications may set 200-500ms) to prevent per-character timing side-channel analysis. The `data-ars-state` attribute should not change to `"completed"` until after the delay.
713	
714	## 5. Form Integration
715	
716	- **Hidden input**: A single `<input type="hidden">` via `HiddenInput` submits the concatenated pin value. The `name` attribute comes from context.
717	- **Validation states**: `aria-invalid="true"` on each cell input when `invalid=true`. The `ErrorMessage` part is linked via `aria-describedby` on the Root.
718	- **Error message association**: The group Root element can reference Description and ErrorMessage via `aria-describedby`.
719	- **Reset behavior**: On form reset, the adapter restores all cells to `default_value` and transitions to Idle.
720	- **Disabled propagation**: When inside a `Field` or `Fieldset`, the adapter merges `disabled` from `FieldCtx` per `07-forms.md` §12.6.
721	
722	## 6. Library Parity
723	
724	> Compared against: Ark UI (`PinInput`), Radix UI (`OneTimePasswordField` preview).
725	
726	### 6.1 Props
727	
728	| Feature          | ars-ui                        | Ark UI                                   | Radix UI                   | Notes          |
729	| ---------------- | ----------------------------- | ---------------------------------------- | -------------------------- | -------------- |
730	| Controlled value | `value: Option<Vec<String>>`  | `value: string[]`                        | `value: string`            | Full parity    |
731	| Default value    | `default_value: Vec<String>`  | `defaultValue`                           | `defaultValue`             | Full parity    |
732	| Length           | `length: usize`               | `count`                                  | (derived from Input count) | Full parity    |
733	| Disabled         | `disabled: bool`              | `disabled`                               | `disabled`                 | Full parity    |
734	| Invalid          | `invalid: bool`               | `invalid`                                | --                         | Ark parity     |
735	| Read-only        | `readonly: bool`              | `readOnly`                               | `readOnly`                 | Full parity    |
736	| Required         | `required: bool`              | `required`                               | --                         | Ark parity     |
737	| OTP mode         | `otp: bool`                   | `otp`                                    | `autoComplete`             | Full parity    |
738	| Mask             | `mask: bool`                  | `mask`                                   | `type: "password"`         | Full parity    |
739	| Placeholder      | `placeholder: Option<String>` | `placeholder`                            | `placeholder`              | Full parity    |
740	| Mode             | `mode: Mode`                  | `type` (numeric/alphanumeric/alphabetic) | `validationType`           | Full parity    |
741	| Form name        | `name: Option<String>`        | `name`                                   | `name`                     | Full parity    |
742	| Form ID          | `form: Option<String>`        | `form`                                   | `form`                     | Full parity    |
743	| Select on focus  | `select_on_focus: bool`       | `selectOnFocus`                          | --                         | Ark parity     |
744	| Blur on complete | `blur_on_complete: bool`      | `blurOnComplete`                         | --                         | Ark parity     |
745	| Auto-submit      | `auto_submit: bool`           | --                                       | `autoSubmit`               | Radix parity   |
746	| Pattern          | --                            | `pattern`                                | `sanitizeValue`            | See note below |
747	
748	**Gaps:** None material. Ark's `pattern` prop is a regex filter; ars-ui's `Mode` enum provides the same filtering. Radix's `sanitizeValue` callback is more flexible but only applies when `validationType: "none"`.
749	
750	### 6.2 Anatomy
751	
752	| Part             | ars-ui                 | Ark UI                      | Radix UI      | Notes                                            |
753	| ---------------- | ---------------------- | --------------------------- | ------------- | ------------------------------------------------ |
754	| Root             | `Root`                 | `Root`                      | `Root`        | Full parity                                      |
755	| Label            | `Label`                | `Label`                     | --            | Ark parity                                       |
756	| Input (per cell) | `Input { cell_index }` | `Input` (with `index` prop) | `Input`       | Full parity                                      |
757	| HiddenInput      | `HiddenInput`          | `HiddenInput`               | `HiddenInput` | Full parity                                      |
758	| Control          | --                     | `Control`                   | --            | Ark layout wrapper; ars-ui Root serves this role |
759	| Description      | `Description`          | --                          | --            | ars-ui form-field part                           |
760	| ErrorMessage     | `ErrorMessage`         | --                          | --            | ars-ui form-field part                           |
761	
762	**Gaps:** None.
763	
764	### 6.3 Events
765	
766	| Callback      | ars-ui                                   | Ark UI               | Radix UI             | Notes                                |
767	| ------------- | ---------------------------------------- | -------------------- | -------------------- | ------------------------------------ |
768	| Value changed | `InputChar`/`DeleteChar`                 | `onValueChange`      | `onValueChange`      | Full parity                          |
769	| Completed     | `Complete(String)` / `on_value_complete` | `onValueComplete`    | `onAutoSubmit`       | Full parity                          |
770	| Invalid input | via `Mode` filtering                     | `onValueInvalid`     | --                   | Ark parity (ars-ui silently rejects) |
771	| Paste         | `Paste(String)`                          | (handled internally) | (handled internally) | Full parity                          |
772	
773	**Gaps:** None.
774	
775	### 6.4 Features
776	
777	| Feature               | ars-ui | Ark UI | Radix UI |
778	| --------------------- | ------ | ------ | -------- |
779	| Auto-advance on input | Yes    | Yes    | Yes      |
780	| Backspace navigation  | Yes    | Yes    | Yes      |
781	| Paste support         | Yes    | Yes    | Yes      |
782	| OTP autocomplete      | Yes    | Yes    | Yes      |
783	| Masked display        | Yes    | Yes    | Yes      |
784	| Form integration      | Yes    | Yes    | Yes      |
785	| IME composition       | Yes    | --     | --       |
786	
787	**Gaps:** None.
788	
789	### 6.5 Summary
790	
791	- **Overall:** Full parity with both reference libraries.
792	- **Divergences:** ars-ui uses `Vec<String>` per-cell value vs. Radix's single string. ars-ui uses a `Mode` enum instead of Ark's string `type` prop. ars-ui adds IME composition tracking.
793	- **Recommended additions:** None.
